CREATE TABLE integration_events (
  id text primary key,
  provider text not null,
  event_id text,
  event_type text,
  signature_valid integer not null default 0,
  payload text not null,
  status text not null,
  error text,
  created_at text not null default current_timestamp,
  processed_at text
);
CREATE TABLE ai_provider_config (
  id text primary key,
  enabled integer not null default 0,
  base_url text not null,
  image_model text not null,
  review_model text not null default 'gpt-4.1-mini',
  temporary_key_ttl_minutes integer not null default 60,
  temporary_key_quota integer not null default 100,
  created_at text not null default current_timestamp,
  updated_at text not null default current_timestamp
, api_key_encrypted text, newapi_key_encrypted text, newapi_management_base_url text not null default '', newapi_user_id text not null default '', llm_api_models text);
CREATE TABLE ai_image_jobs (
  id text primary key,
  user_id text not null,
  application_id text,
  model text not null,
  prompt text not null,
  status text not null,
  r2_object_key text,
  content_type text,
  error text,
  created_at text not null default current_timestamp,
  completed_at text,
  updated_at text not null default current_timestamp
);
CREATE TABLE ai_temporary_keys (
  id text primary key,
  user_id text not null,
  key_hash text not null,
  upstream_token_id text,
  quota integer not null,
  expires_at text not null,
  revoked_at text,
  created_at text not null default current_timestamp
, name text, key_masked text, status text not null default 'active', provider text not null default 'newapi');
CREATE TABLE notifications (
  id text primary key,
  user_id text not null,
  event text not null,
  title text not null,
  body text not null,
  data text not null default '{}',
  read_at text,
  created_at text not null default current_timestamp
);
