CREATE TABLE push_subscriptions (
  id text primary key,
  user_id text not null,
  endpoint text not null unique,
  p256dh text not null,
  auth text not null,
  user_agent text,
  enabled integer not null default 1,
  disabled_at text,
  created_at text not null default current_timestamp,
  updated_at text not null default current_timestamp
);
CREATE TABLE github_app_config (
  id text primary key,
  enabled integer not null default 0,
  app_name text not null default '',
  app_slug text not null default '',
  client_id text not null,
  client_secret text not null,
  callback_url text not null,
  authorize_url text not null,
  token_url text not null,
  api_base_url text not null,
  scopes text not null,
  created_at text not null default current_timestamp,
  updated_at text not null default current_timestamp
, client_secret_encrypted text);
CREATE TABLE notification_provider_config (
          id text primary key,
          resend_api_key_encrypted text,
          resend_from_email text not null default '',
          vapid_public_key text not null default '',
          vapid_private_key_encrypted text,
          vapid_subject text not null default '',
          created_at text not null default current_timestamp,
          updated_at text not null default current_timestamp
        , feishu_mail_enabled integer not null default 0, feishu_app_id text not null default '', feishu_app_secret_encrypted text, feishu_user_access_token_encrypted text, feishu_refresh_token_encrypted text, feishu_access_token_expires_at text, feishu_refresh_token_expires_at text, feishu_user_mailbox_id text not null default 'me', feishu_site_base_url text not null default '', feishu_daily_limit integer not null default 400);
