INSERT INTO "welfare_applications" ("id","user_id","type","status","title","payload","created_at","updated_at") VALUES('app_mq3xnnwe_nkxmpd','oauth_linux-do_4e328cebf541d32f08195b76','resource','approved','资源申请','{"id":"app_mq3xnnwe_nkxmpd","userId":"oauth_linux-do_4e328cebf541d32f08195b76","type":"resource","title":"资源申请","description":"<p><!--StartFragment-->佬，目前我是一名硕士研究生，然后今年在用 ai 辅助做科研，科研做的是三维牙齿分割模型，主要就是利用 sam3d 强大的泛化能力，实现 mask，然后训练 3d 模型进行牙齿扫描模型（主要是 3d 模型）的牙齿分割，之前一直用的 team 订阅中的 pro 模型，但是最近被封了，只能用 plus 的模型，很明显能感受到 pro 和 plus 之间的差距。另外接下来我也要开始写论文了，需要用到 pro 和生图，希望能得到佬的支持。谢谢佬<!--EndFragment--></p>","hasOpenSourceBadge":false,"attachments":[{"id":"att_mq3xnnkn_rl4yjw","name":"微信图片_20260607130425_130_148.jpg","size":1755290,"type":"image/jpeg","r2Key":"user-uploads/oauth_linux-do_4e328cebf541d32f08195b76/att_mq3xnnkn_rl4yjw.jpg","url":"/api/uploads/att_mq3xnnkn_rl4yjw/file"},{"id":"att_mq3xnmon_bo2b08","name":"微信图片_20260607130432_131_148.jpg","size":77538,"type":"image/jpeg","r2Key":"user-uploads/oauth_linux-do_4e328cebf541d32f08195b76/att_mq3xnmon_bo2b08.jpg","url":"/api/uploads/att_mq3xnmon_bo2b08/file"},{"id":"att_mq3xnmq7_v9nx9o","name":"微信图片_20260607130542_132_148.png","size":154209,"type":"image/png","r2Key":"user-uploads/oauth_linux-do_4e328cebf541d32f08195b76/att_mq3xnmq7_v9nx9o.png","url":"/api/uploads/att_mq3xnmq7_v9nx9o/file"}],"status":"approved","baseCost":10998,"cost":770,"costCharged":true,"couponDiscountAmount":0,"sharedToSquare":false,"squareDiscountRate":1,"squareDiscountAmount":0,"pricingDiscountRate":0.07001272958719768,"pricingPromotionName":"限时 0.1 折","pricingPromotionEndsAt":"2026-06-08T00:00:00.000Z","pricingAppliedAt":"2026-06-07T15:24:40.765Z","aiReviewFeeRate":0.3,"rejectionReviewFee":0,"rejectionReviewFeeWaived":true,"rejectionFraudulent":false,"storageExtended":false,"storageExtensionCost":0,"retentionExpiresAt":"2026-06-14T15:24:40.765Z","standardProcessingHours":72,"processingDueAt":"2026-06-10T15:24:40.765Z","contextAppendUntil":"2026-0