INSERT INTO "welfare_applications" ("id","user_id","type","status","title","payload","created_at","updated_at") VALUES('app_mq4x6c4h_806ook','oauth_linux-do_dcd5ff3c13d10ade90185e01','resource','draft','写机器学习课程论文，codex资源申请','{"id":"app_mq4x6c4h_806ook","userId":"oauth_linux-do_dcd5ff3c13d10ade90185e01","type":"resource","title":"写机器学习课程论文，codex资源申请","description":"<p>&lt;!--StartFragment--&gt;您好！在准备本次机器学习课程论文的过程中，我计划将主要精力集中于核心算法的设计、理论推导以及模型结构的创新上。为了提高基础代码编写和数据预处理的效率，避免在常规语法格式上耗费过多时间，我恳请批准在论文的实验代码编写环节使用 Codex 进行辅助。论文的核心逻辑、算法架构以及最终的实验分析均由我本人独立思考与完成。Codex 仅作为提升开发效率的基础辅助工具，且我会对所有辅助生成的代码进行严格的审查与测试，确保完全符合学术规范与课程要求。希望能得到您的批准，谢谢！&lt;!--EndFragment--&gt;&lt;!--EndFragment--&gt;</p>","hasOpenSourceBadge":false,"attachments":[{"id":"mq4x4j6m_zoy3o3","name":"《基于MATLAB的机器学习入门》课程论文要求.pptx","size":428787,"type":"application/vnd.openxmlformats-officedocument.presentationml.presentation"},{"id":"mq4x4j6m_nit8tp","name":"10 降维算法和竞争网络.pdf","size":2654983,"type":"application/pdf"},{"id":"mq4x4j6m_sp2kho","name":"《机器学习》课程论文参考.pdf","size":788311,"type":"application/pdf"},{"id":"mq4x4j6m_98joyq","name":"课程论文（双排）模板.doc","size":1211392,"type":"application/msword"}],"status":"draft","baseCost":0,"cost":0,"costCharged":false,"sharedToSquare":false,"pricingDiscountRate":1,"pricingAppliedAt":"2026-06-08T08:00:49.576Z","aiReviewFeeRate":0.3,"rejectionReviewFee":0,"rejectionReviewFeeWaived":true,"rejectionFraudulent":false,"storageExtended":false,"storageExtensionCost":0,"retentionExpiresAt":"2026-06-15T08:00:49.576Z","standardProcessingHours":72,"processingDueAt":"2026-06-11T08:00:49.576Z","contextAppendUntil":"2026-06-15T08:00:49.576Z","reason":"<p><!--StartFragment-->您好！在准备本次机器学习课程论文的过程中，我计划将主要精力集中于核心算法的设计、理论推导以及模型结构的创新上。为了提高基础代码编写和数据预处理的效率，避免在常规语法格式上耗费过多时间，我恳请批准在论文的实验代码编写环节使用 Codex 进行辅助。论文的核心逻辑、算法架构以及最终的实验分析均由我本人独立思考与完成。Codex 仅作为提升开发效率的基础辅助工具，且我会对所有辅助生成的代码进行严格的审查与测试，确保完全符合学术规范与课程要求。希望能得到您的批准，谢谢！<!--EndFragment--><!--EndFragment--></p>","businessBackground":"","urgency":"normal","expectedEffec