CREATE TABLE user_coupons (
          id text primary key,
          user_id text not null,
          name text not null,
          scope text,
          discount_type text,
          discount_rate real not null,
          discount_amount integer,
          payload text not null,
          created_at text not null,
          expires_at text,
          used_at text
        );
CREATE TABLE database_provision_config (
          id text primary key,
          enabled integer not null default 0,
          root_url_encrypted text,
          default_expires_in_days integer not null default 30,
          database_prefix text not null default 'twg',
          onepanel_base_url text not null default '',
          onepanel_api_key_encrypted text,
          created_at text not null default current_timestamp,
          updated_at text not null default current_timestamp
        );
CREATE TABLE database_resource_bindings (
          id text primary key,
          user_id text not null,
          application_id text not null,
          item_id text not null,
          database_type text not null,
          database_name text not null,
          username text not null,
          password_hash text not null,
          connection_url_encrypted text,
          connection_url_masked text not null,
          permission text not null,
          expires_at text,
          status text not null,
          created_at text not null default current_timestamp,
          revoked_at text
        );
CREATE TABLE sub2api_resource_provision_locks (
          id text primary key,
          owner text not null,
          expires_at text not null,
          created_at text not null default current_timestamp
        );
CREATE TABLE system_logs (
          id text primary key,
          level text not null,
          module text not null,
          action text not null,
          message text not null,
          details text not null default '{}',
          ref_id text,
          duration_ms integer,
          created_at text not null default current_timestamp
        );
